  7→} from "../be/db";
  8→import type { RetryPolicy } from "../types";
  9→import { checkpointStep, checkpointStepFailure } from "./checkpoint";
 10→import { getSuccessors } from "./definition";
 11→import { walkGraph } from "./engine";
 12→import type { ExecutorRegistry } from "./executors/registry";
 13→import { deepInterpolate } from "./template";
 14→
 15→let pollerTimeout: ReturnType<typeof setTimeout> | null = null;
 16→
 17→/**
 18→ * Start the retry poller.
 19→ *
 20→ * Uses setTimeout chaining (not setInterval) to prevent overlap —
 21→ * the next tick is scheduled only after the current one completes.
 22→ */
 23→export function startRetryPoller(registry: ExecutorRegistry, intervalMs = 5000): void {
 24→  if (pollerTimeout !== null) return; // Already running
 25→
 26→  async function poll(): Promise<void> {
 27→    try {
 28→      const retryableSteps = getRetryableSteps();
 29→
 30→      for (const step of retryableSteps) {
 31→        try {
 32→          const run = getWorkflowRun(step.runId);
 33→          if (!run) continue;
 34→
 35→          const workflow = getWorkflow(run.workflowId);
 36→          if (!workflow) continue;
 37→
 38→          // Find the node definition for this step
 39→          const node = workflow.definition.nodes.find((n) => n.id === step.nodeId);
 40→          if (!node) continue;
 41→
 42→          console.log(
 43→            `[workflows] Retrying step ${step.nodeId} (attempt ${step.retryCount}) for run ${step.runId}`,
 44→          );
 45→
 46→          // If the run was failed (due to this step), set it back to running
 47→          if (run.status === "failed") {
 48→            updateWorkflowRun(run.id, {
 49→              status: "running",
 50→              error: undefined,
 51→            });
 52→          }
 53→
 54→          // Clear the retry marker so this step isn't picked up again
 55→          updateWorkflowRunStep(step.id, {
 56→            status: "running",
 57→            error: undefined,
 58→            nextRetryAt: undefined,
 59→          });
 60→
 61→          const ctx = (run.context ?? {}) as Record<string, unknown>;
 62→
 63→          // Deep-interpolate config
 64→          const { value: interpolatedValue } = deepInterpolate(node.config, ctx);
 65→          const interpolatedConfig = interpolatedValue as Record<string, unknown>;
 66→
 67→          // Get executor and re-run
 68→          const executor = registry.get(node.type);
 69→          const meta = {
 70→            runId: run.id,
 71→            stepId: step.id,
 72→            nodeId: step.nodeId,
 73→            workflowId: workflow.id,
 74→            dryRun: false,
 75→          };
 76→
 77→          try {
 78→            const result = await executor.run({
 79→              config: interpolatedConfig,
 80→              context: ctx,
 81→              meta,
 82→            });
 83→
 84→            if (result.status === "failed") {
 85→              // Re-failed — use the EXISTING retryCount from the step.
 86→              // checkpointStepFailure handles marking run as failed if no retries left,
 87→              // or setting nextRetryAt for the next poll cycle.
 88→              const retryPolicy = node.retry || executor.retryPolicy;
 89→              checkpointStepFailure(
 90→                run.id,
 91→                step.id,
 92→                result.error || "Retry failed",
 93→                step.retryCount,
 94→                retryPolicy,
 95→              );
 96→            } else {
 97→              // Success! Checkpoint and continue the graph
 98→              checkpointStep(run.id, step.id, step.nodeId, result, ctx);
