   158→      expect(calculateDelay(policy, 1)).toBe(1000);
   159→      expect(calculateDelay(policy, 5)).toBe(1000);
   160→    });
   161→
   162→    test("linear backoff scales with attempt", () => {
   163→      const policy: RetryPolicy = {
   164→        strategy: "linear",
   165→        maxRetries: 5,
   166→        baseDelayMs: 1000,
   167→        maxDelayMs: 30000,
   168→      };
   169→      expect(calculateDelay(policy, 0)).toBe(1000); // 1000 * 1
   170→      expect(calculateDelay(policy, 1)).toBe(2000); // 1000 * 2
   171→      expect(calculateDelay(policy, 2)).toBe(3000); // 1000 * 3
   172→    });
   173→
   174→    test("linear backoff is capped at maxDelayMs", () => {
   175→      const policy: RetryPolicy = {
   176→        strategy: "linear",
   177→        maxRetries: 10,
   178→        baseDelayMs: 5000,
   179→        maxDelayMs: 15000,
   180→      };
   181→      expect(calculateDelay(policy, 5)).toBe(15000); // 5000 * 6 = 30000, capped at 15000
   182→    });
   183→
   184→    test("exponential backoff returns value within bounds", () => {
   185→      const policy: RetryPolicy = {
   186→        strategy: "exponential",
   187→        maxRetries: 5,
   188→        baseDelayMs: 100,
   189→        maxDelayMs: 10000,
   190→      };
   191→
   192→      // Run multiple times to verify it's within bounds (jitter is random)
   193→      for (let i = 0; i < 20; i++) {
   194→        const delay = calculateDelay(policy, 2);
   195→        expect(delay).toBeGreaterThanOrEqual(0);
   196→        expect(delay).toBeLessThanOrEqual(10000);
   197→      }
   198→    });
   199→
   200→    test("exponential backoff grows with attempt", () => {
   201→      const policy: RetryPolicy = {
